function onSubmitUpdatePlan() {
  if (!stepTwoSaveData.value) {
    return;
  }
  const save = stepTwoSaveData.value;

  // 组装参数
  const params: UpdatePlanParams = {
    schedule_list: save.tasksList.map((item) => {
      return {
        schedule_id: item.schedule_id,
        start_time: item.start_time,
        end_time: item.end_time,
      };
    }) as Array<ScheduleListItem>,
    week_rule: save.weekChecked.join(","),
    group_type: groupType.value as number,
    group_id: groupId.value,
  };

  // 提交修改
  updatePlan(params)
    .then((response) => {
      const res = response.data;
      if (res.errcode === 0) {
        // 修改成功，返回上一页并且toast提示
        window.ConnectWebViewBridgeSDK.newCallBridgeFn(
          "showToast",
          "调整计划时间已成功，任务排序已更新"
        );
        window.ConnectWebViewBridgeSDK.newCallBridgeFn("skillGoback", {});
      } else {
        window.ConnectWebViewBridgeSDK.newCallBridgeFn("showToast", "提交失败");
      }
    })
    .catch(() => {
      // 无网络提示
      if (!window.navigator.onLine) {
        window.ConnectWebViewBridgeSDK.newCallBridgeFn(
          "showToast",
          "无网络连接"
        );
      } else {
        window.ConnectWebViewBridgeSDK.newCallBridgeFn("showToast", "提交失败");
      }
    });
}

