        start_time: item.start_time,
        end_time: item.end_time,
        ...(item.content_id
          ? {
              content_id: item.content_id,
              content_type: item.content_type,
              template_id: item.template_id,
            }
          : {}),
        task_list: item.sub_tasks?.map((task) => {
          const val = taskList.find(
            (item) => task.sub_task_id === item.task_id
          );
          return {
            task_id: task.sub_task_id,
            task_type: task.sub_task_type,
            task_name: task.sub_task_name,
            finish_rate: task.sub_task_progress,
            ...(val
              ? {
                  finish_time: val.finish_time,
                  expand: val.expand,
                }
              : {}),
          };
        }),
      };
    });
    const params = {
      schedule_list: scheduleList,
      week_rule: stepTwoSaveData.value?.weekChecked.join(","),
      group_type: Number(groupType.value as number),
      group_id: groupId.value,
      stu_tal_id: "",
      old_schedule_list: planList.value
        .filter((item) => stepOneCheckList.value.includes(item.schedule_id))
        .map((item) => ({
          schedule_id: item.schedule_id,
          start_time: item.start_time,
          end_time: item.end_time,
        })),
    };
    batchModifyCapacity(params).then((res) => {
      if (res.data.errcode === 0) {
        // 跳转到计划详情
        setTimeout(() => {
          Toast(`任务容量调整成功`);
          track("task_capacity_assign_toast", {
            toast_type: "任务容量调整成功",
          });
        }, 1000);
        router.go(-1);
      }
    });
  } catch (e) {
    console.log(e);
  }
