import sensors from "@/utils/sensors";
// 私有变量, 用于存储默认配置
let defaultConfig = {}

const track = (type: string, obj = {}) => {
    sensors.track(type, {
        ...defaultConfig,
        ...obj,
    });
};
const setDefaultConfig = (obj: any) => {
    defaultConfig = obj
}

export {
    track,
    setDefaultConfig
}

