import ApiService, {ResponseType} from '@/api/api'
import { CourseDetail, GetCourseDetailParams, PlanIncomplete, UpdatePlanParams } from '../types'
import { getUserInfo } from "@/views/CustomTaskList/api";

export const getPlanIncomplete = (params: {
  groupId: string;
  groupType: number;
}): ResponseType<PlanIncomplete> => {
  return ApiService.post('/xpad2/schedule/v2/group/plan-incomplete', {
    group_id: params.groupId,
    group_type: params.groupType,
  });
} 
// 获取未完成计划
export const getPlanIncompleteII = async (data: any) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/group/plan-incomplete/tree", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
}
