import {
  ContentsObject
} from '../types2';
import useCommon from './useCommon';

export default () => {
  /**
   * @description: 判断是否是最后一层
   * @param {ContentsObject} item
   * @param {number} type
   * @return {*}
   */ 
  const { getMultiSkuList, getMultiSkuFloor } = useCommon();

  const checkIsLastFloor = (item: ContentsObject, type:number) => {
    if ((item.floor === type) || !item.hasChildren && (item.floor < type)) {
      return true
    }
    return false
  }

  /**
   * @description: 判断是否是子节点
   * @param {ContentsObject} item
   * @param {number} type
   * @return {*}
   */  
  const checkIsChild = (item: ContentsObject, type:number) => {
    return !item.hasChildren && item.floor < type
  }
  
  /**
   * @description: 获取最顶部的层级
   * @param {ContentsObject} list
   * @param {number} index
   * @return {*}
   */  
  const checkTopLen = (list: ContentsObject[], index: number) => {
    let n = 1
    const findTop = () => {
      if (list[index-n] && list[index-n].hasChildren) {
        n++
        findTop()
      } else {
        return
      }
    }
    findTop()
    return n-1
  }
  
  /**
   * @description: 计算次数
   * @param {ContentsObject} arr
   * @param {number} type
   * @param {number} times
   * @return {*}
   */  
  const calculateNum = (list: ContentsObject[], type: number, times: number) => {
    let index = 0
    let timesIndex = 0
    const arr = list.reduce((prev: ContentsObject[], cur) => {
      const val = list.some((item) => item.parentKeys.includes(cur.key) && item.floor === type)
      if (val || cur.floor >= type) {
        prev.push(cur)
      }
      return prev;
    }, []);
    arr.forEach((item: ContentsObject) => {
      if(checkIsLastFloor(item, type)) {
        index++
        if ((index % times === 1 || times === 1) && !checkIsChild(item, type)) {
          timesIndex++
        }
        if (checkIsChild(item, type)) {
          index = 0
          timesIndex++
        }
      }
    })
    return timesIndex
  }

  const getMultiSkuCalculateNum = (list: ContentsObject[], type: number, times: number) => {
    const multiSkuList = getMultiSkuList(list);

    return multiSkuList.reduce((prev: number, item) => {
      let floor = type;
      if (multiSkuList.length > 1) {
        const curFloor = getMultiSkuFloor(item, type);
        floor = curFloor <= 0 ? type: curFloor;
      }
      return prev + calculateNum(item, floor, times);
    }, 0);
  }

  return {
    checkIsLastFloor,
    checkIsChild,
    checkTopLen,
    calculateNum,
    getMultiSkuCalculateNum
  }
}