import { UPDATE_CONTENT_TYPE } from '../config';
import { ContentsObject, CustomPlanObject, SubTask, taskObject } from '../types2'
import { cloneDeep } from 'lodash';

export default () => {
/**
   * @description: 秒时间格式化
   * @param {second} second
   * @return {string}
   */ 
  const formatSecond = (second: number) => {
    if (second === 0) {
      return '';
    }
    if (second < 60) {
      return '1分钟';
    }
    let timeStr = '';
    const hours = Math.floor(second / 3600);
    const minutes = Math.floor((second % 3600) / 60);

    if (hours) {
      timeStr += hours + '小时';
    }

    if (minutes) {
      timeStr += minutes + '分钟';
    }

    return timeStr;
    
  }



  /**
   * @description: 分钟时间格式化
   * @param {number} minutes
   * @return {string}
   */  
  const filterMiutes = (minutes: number) => {
    if (minutes < 60) {
      return minutes + "分钟";
    } else {
      const hours = Math.floor(minutes / 60);
      const remainingMinutes = minutes % 60;
      if (remainingMinutes === 0) {
        return hours + "小时";
      } else {
        return hours + "小时" + remainingMinutes + "分钟";
      }
    }
  }
  
  /**
   * @description: 获取总时间/总字数
   * @param {any} list
   * @return {*}
   */  
  const getTotalSecond  = (list: any) => {
    let total = 0
    list.forEach((item: any) => {
      if (item.checked && !item.hasChildren) {
        total += Number(item.learn_time)
      }
    })
    return total
  }

    /**
   * @description: 获取总时间/总字数
   * @param {any} list
   * @return {*}
   */  
    const getTotalTime = (list: any, capacityType = 1) => {
      if (capacityType === 1) {
        return getTotalSecond(list)
      }
      let total = 0
      list.forEach((item: any) => {
        if (item.checked && !item.hasChildren) {
          total += Number(item.capacity_value)
        }
      })
      return total
    }

  /**
   * @description: 计算平均时间/字数
   * @param {number} totalNum
   * @param {number} currentTimes
   * @return {*}
   */  
  const calcAverageNum = (totalNum: number, currentTimes: number) => {
    const avarageNum = totalNum / currentTimes
    return avarageNum < 1 ? 1 :  Math.round(avarageNum)
  }
  
  /**
   * @description: 过滤文字
   * @param {string} name
   * @return {*}
   */  
  const filterResourceTitle = (name: string) => {
    if (name && name.length > 20) {
      return name.slice(0, 20) + '...'
    }
    return name
  }
  
  /**
   * @description: 过滤所有选中的数组
   * @param {ContentsObject[]} arr
   * @return {*}
   */  
  const filterChecked = (arr: ContentsObject[]) => {
    const result:ContentsObject[] = [];
    for (let i = 0; i < arr.length; i++) {
      if (arr[i].checkedState === 'selected' || arr[i].checkedState === 'halfSelected') {
        result.push(arr[i]);
      }
    }
    return result;
  }
  
  /**
   * @description: 过滤任务列表
   * @param {ContentsObject} list
   * @param {string} resource_title
   * @return {*}
   */  

  const getAllSkuTaskList = (params: {
    list: ContentsObject[];
    resource_title: string;
    gradeSubjects?: string;
    floor: number;
    templateIdMap: {[key: string]: number}
    currentPlanType: number;
    isUpdatePlan?: boolean;
  }) => {
    const { list, currentPlanType, floor, isUpdatePlan = false } = params;
    const multiSkuList = getMultiSkuList(list);


    let myTimes = 0
    const arr = multiSkuList.map((item) => {
      let type = floor;
      if (multiSkuList.length > 1) {
        const curFloor = getMultiSkuFloor(item, type);
        type = curFloor <= 0 ? type: curFloor;
      }
      
      const newParams = {
        ...params,
        list: item,
        num: myTimes,
        floor: type
      }
      const newList = UPDATE_CONTENT_TYPE.includes(item[0].course_type)
        && currentPlanType !== 5
        && currentPlanType !== 6
        && !isUpdatePlan
          ? getTaskList(newParams) : filterTaskList(newParams)
      myTimes += newList.length;
      return newList;
    }).flat();

    return arr;

  }

  const filterTaskList = (params: {
    list: ContentsObject[];
    resource_title: string;
    gradeSubjects?: string;
    floor: number;
    templateIdMap: {[key: string]: number};
    num?: number;
  }) => {
    const {list, resource_title, gradeSubjects = '', floor, templateIdMap, num = 0} = params;
    let myTimes = num;
    return list.reduce((pre:any, cur:any) => {
      if (cur['myArray'] && cur['myArray'].length) {
        pre.push({
          task_name: gradeSubjects + resource_title + '计划 第' + (++myTimes) + '次',
          start_time: 0,
          end_time: 0,
          unit_num: cur.unitNum,
          unit_name: cur.unitName,
          totalTime: cur.totalTime,
          unitNum: cur.unitNum,
          unitName: cur.unitName,
          sub_tasks: [],
          ...cur.course_id !== '0' 
            ? {
              content_id: cur.course_id ,
              content_type: cur.course_type,
              template_id: templateIdMap[cur.course_id]
            }
            : {}
        })
        if(!cur.hasChildren) {
          const parentId = list.find(val => cur.parentKeys.includes(val.key) && val.floor === floor)?.content_id || cur.content_id;
          pre[pre.length-1]['sub_tasks'].push({
            type: 1,
            sub_task_id: cur.content_id,
            sub_task_type: cur.content_type,
            sub_task_name: cur.content_name,
            sub_task_progress: cur.learn_progress,
            sub_parent_task_id: parentId
          })
        }
      } else {
        if(!cur.hasChildren) {
          const parentId = list.find(val => cur.parentKeys.includes(val.key) && val.floor === floor)?.content_id || cur.content_id;
          pre[pre.length - 1]['sub_tasks'].push({
            type: 2,
            sub_task_id: cur.content_id,
            sub_task_type: cur.content_type,
            sub_task_name: cur.content_name,
            sub_task_progress: cur.learn_progress,
            sub_parent_task_id: parentId,
          })
        }
      }
      return pre
    }, [])
  }

  const getTaskList = (params: {
    list: ContentsObject[];
    resource_title: string;
    gradeSubjects?: string;
    floor: number;
    templateIdMap: {[key: string]: number},
    num?: number
  }) => {
    const {list, resource_title, gradeSubjects = '', floor, templateIdMap, num = 0} = params;
    let myTimes = num;
    const floorList = list.filter(item => item.floor <= floor || (item.myArray && item.myArray.length));

    const newList = floorList.reduce((pre: any, cur: ContentsObject) => {
      if (cur['myArray'] && cur['myArray'].length) {
        pre.push({
          task_name: gradeSubjects + resource_title + '计划 第' + (++myTimes) + '次',
          start_time: 0,
          end_time: 0,
          totalTime: cur.totalTime,
          unit_num: cur.unitNum,
          unit_name: cur.unitName,
          unitNum: cur.unitNum,
          unitName: cur.unitName,
          sub_tasks: [],
          ...cur.course_id !== '0' 
            ? {
              content_id: cur.course_id ,
              content_type: cur.course_type,
              template_id: templateIdMap[cur.course_id]
            }
            : {}
        })
      }

      // if (!cur.hasChildren && floor > cur.floor && cur.checked) {
      //   const parentId = list.find(val => cur.parentKeys.includes(val.key) && val.floor === floor)?.content_id || cur.content_id;
      //   pre[pre.length-1]['sub_tasks'].push({
      //     type: 1,
      //     sub_task_id: cur.content_id,
      //     sub_task_type: cur.content_type,
      //     sub_task_name: cur.content_name,
      //     sub_task_progress: cur.learn_progress,
      //     sub_parent_task_id: parentId
      //   })

      //   return pre;
      // }
      if (floor === cur.floor) {
        // 如果当前没选中直接查找子级
        const subTask = getSubTaskList(cur.content_id, list, floor);
        pre[pre.length-1]['sub_tasks'].push(...formatSubTaskList(subTask, list, floor));
      }
      return pre
    }, []);

    console.log('newList', newList);
  
    return newList;
  }

  // const getSubTaskList = (list: ContentsObject[], originList: ContentsObject[]) => {
  //   const subTaskList: ContentsObject[] = [];
  //   list.forEach(item => {
  //     if (item.checked) {
  //       subTaskList.push(item)
  //     } else {
  //       const childList = originList.filter((val) => val.parentId === item.content_id);
  //       subTaskList.push(...getSubTaskList(childList, originList))
  //     }
  //   });

  //   return subTaskList;
  // }

  const getSubTaskList = (id: string, list: ContentsObject[], floor: number) => {
    const subTaskList: ContentsObject[] = [];
    // 查询当前元素
    const item = list.find((i: ContentsObject) => i.content_id === id);
    if (item) {
      // 判断当前元素是否选中
      if (item.checked) {
        subTaskList.push(item)
      } else {
        // 查找所有的字级
        const childs = list.filter((i: ContentsObject) => i.parentId === id);
        // 递归查找选中的子级
        for (const key in childs) {
          const child = childs[key];
          subTaskList.push(...getSubTaskList(child.content_id, list, floor));
        }
      }
    }

    return subTaskList;
  }

  const formatSubTaskList = (subTask: Array<ContentsObject>, list: Array<ContentsObject>, floor: number) => {
    const subTaskList: Array<SubTask> = [];
    for (const item of subTask) {
      const parentId = list.find(val => item.parentKeys.includes(val.key) && val.floor === floor)?.content_id || item.content_id;
      
      subTaskList.push({
        type: 2,
        sub_task_id: item.content_id,
        sub_task_type: item.content_type,
        sub_task_name: item.content_name,
        sub_task_progress: item.learn_progress,
        sub_parent_task_id: parentId
      });
    }

    return subTaskList;
  }

  const getMultiSkuList = (list: ContentsObject[]) => {
    return Object.values(getMultiSkuObject(list));
  }

  const getMultiSkuObject = (list: ContentsObject[]) => {
    const arrayObject: { [key: string]: ContentsObject[] } = {};
    for (const item of list) {
      if (!item.course_id) {
        continue;
      }
      if (!arrayObject[item.course_id]) {
        arrayObject[item.course_id] = [];
      }
      arrayObject[item.course_id].push(cloneDeep(item));
    }

    return arrayObject;
  }

  const getMultiSkuFloor = (list: ContentsObject[], type: number): number => {
    if (type <= 0) {
      return 0;
    }
    if (list.some(item => item.floor === type)) {
      return type;
    }
  
    return getMultiSkuFloor(list, type - 1);
  }

  
  return {
    filterMiutes,
    formatSecond,
    getTotalTime,
    getTotalSecond,
    calcAverageNum,
    filterResourceTitle,
    filterChecked,
    filterTaskList,
    getTaskList,
    getAllSkuTaskList,
    getMultiSkuList,
    getMultiSkuObject,
    getMultiSkuFloor
  }
}