
import { defineComponent, ref, reactive, watch, nextTick, toRaw, watchEffect, onMounted } from 'vue'
import { Toast } from 'vant';
import dayjs from 'dayjs';
import _ from 'lodash';
import Calendar from './Calendar/index.vue'
// import PlanBaseInfo from './PlanBaseInfo/index.vue'
// import {
//   taskObject,
//   weekTaskObject
// } from '../../../CustomPlan/types';
import {track} from '../track'
export interface taskObject {
  start_time: number | null; // 开始时间
  end_time: number | null; // 结束时间
  show_time: Date | string; // 展示时间
  key: number; // key
  sub_tasks: any; // 子任务列表
  task_name: string; // 任务名称
  totalTime: number; // 总时间
  unitNum: number; // 单位数量
  unitName: string; // 单位名称
  week: string; // 周机场
}
// 周任务列表对象
export interface weekTaskObject {
  name: string; // 周名称
  value: number; // 周值
  isDisabled: boolean; // 是否禁用
}
export default defineComponent({
  components: {
    Calendar,
    // PlanBaseInfo
  },
  props: {
    baseInfo: {
      type: Object,
      default: () => {
        return {
          c: '', // 资源名称
          resource_subtitle: '', // 资源副标题
          capacity_type: 1, // 1:总时长 2:总字数
          learn_frequency_config: {},
          learn_frequency_config_max: {},
          level_names: {} // 级别对应名称
        }
      }
    },
   
    checkList: {
      type: Array,
      default: () => []
    },
    saveData: {
      type: Object,
      default: () => {
        return {}
      }
    },
    weekChecked: {
      type: Array,
      default: () => []
    }
  },
  emits: ['nextStep', 'prevStep'],
  setup(props, { emit }) {
    const calendarRef = ref(null)
    const date = ref(dayjs().format('YYYY-MM-DD'))
    let oldTasksList: any = ref([])
    let tasksList: any = ref([])
    const timeData = reactive({
      startDate: new Date(),
      endDate: null,
      weekChecked: [],
      weekList: [
        { name: '一', value: 1, isDisabled: false },
        { name: '二', value: 2, isDisabled: false },
        { name: '三', value: 3, isDisabled: false },
        { name: '四', value: 4, isDisabled: false },
        { name: '五', value: 5, isDisabled: false },
        { name: '六', value: 6, isDisabled: false },
        { name: '日', value: 7, isDisabled: false }
      ]
    }) as any

    onMounted(() => {
      track('task_capacity_assign_enter',{
        tab:'安排学习时间'
      });
    })

    // 日历
    const isShowCalc = ref<boolean>(false)

    // onMounted(async () => {
    //   const checkedList:any = props.checkList;
    //   timeData.startDate = checkedList[0].start_time ? new Date(checkedList[0].start_time * 1000) : new Date();
    //   timeData.endDate = new Date(checkedList[checkedList.length - 1].end_time * 1000);
    //   setTimeout(() => {
    //     for (const item of  props.weekChecked) {
    //       const val = timeData.weekList.find((week: any) => week.value === item);
    //       if (val) {
    //         handleCheckWeek(val, false);
    //       }
    //     }
    //   })
    // });

    const stopWatcher = watchEffect(() => {
      if (!tasksList.value.length || !props.checkList.length) {
        return;
      }
      const checkedList: any = props.checkList;
      timeData.startDate = checkedList[0].start_time ? new Date(checkedList[0].start_time * 1000) : new Date();
      for (const item of props.weekChecked) {
        const val = timeData.weekList.find((week: any) => week.value === item);
        if (val) {
          handleCheckWeek(val, false);
        }
      }
      stopWatcher();
    }, { flush: 'post' })

    const showCalc = () => {
      isShowCalc.value = true;
    }
    const handleCancel = () => {
      isShowCalc.value = false
    }

    // 转化为周几
    const transforWeek = (date: Date) => {
      const week = dayjs(date).day() === 0 ? 7 : dayjs(date).day();
      return `周${timeData.weekList[week === 0 ? 6 : week - 1]['name']}`
    }

    // 判断是否超过任务总数
    const isPassTotal = ref<boolean>(false);

    // 计算任务结束日期
    const calcEndDate = () => {
      const weekChecked = timeData.weekChecked.sort()
      const startDate = timeData.startDate
      console.log('startDate', startDate);
      const taskLen = tasksList.value.length
      if (weekChecked.length === 0) {
        timeData.endDate = null
        tasksList.value.map((item: taskObject) => {
          item['start_time'] = null
          item['end_time'] = null
          item['show_time'] = ''
          item['week'] = ''
        })
        return
      }
      const dayOfWeek = dayjs(startDate).day() === 0 ? 7 : dayjs(startDate).day();
      const myWeek = weekChecked.filter((item: number) => item >= dayOfWeek)
      let indx = 0;
      let weekIndex = 0;
      let totalWeeks = Math.ceil(taskLen / weekChecked.length);
      tasksList.value.map((item: taskObject, index: number) => {
        if (index < myWeek.length) {
          const beforeDate = dayjs(startDate).add(myWeek[index] - dayOfWeek, 'day').format('YYYY-MM-DD')
          const beforeEndDate = beforeDate + ' 23:59:59'
          item['start_time'] = dayjs(beforeDate).unix()
          item['end_time'] = dayjs(beforeEndDate).unix()
          item['show_time'] = dayjs(beforeEndDate).toDate()
          item['week'] = timeData.weekList[dayjs(beforeDate).day() === 0 ? 6 : dayjs(beforeDate).day() - 1]['name']
          totalWeeks = totalWeeks - 1
        } else {
          const myStartDate = dayjs(startDate).add(7 - dayOfWeek, 'day').toDate()
          const afterDate = dayjs(myStartDate).add(weekChecked[indx] + weekIndex * 7, 'day').format('YYYY-MM-DD')
          const afterEndDate = afterDate + ' 23:59:59'
          item['start_time'] = dayjs(afterDate).unix()
          item['end_time'] = dayjs(afterEndDate).unix()
          item['show_time'] = dayjs(afterEndDate).toDate()
          item['week'] = timeData.weekList[dayjs(afterDate).day() === 0 ? 6 : dayjs(afterDate).day() - 1]['name']
          if (indx >= weekChecked.length - 1) {
            indx = 0
            weekIndex++
          } else {
            indx++
          }
        }
      })
      // console.log('我的任务', tasksList.value)
      timeData.endDate = tasksList.value.length ? tasksList.value[tasksList.value.length - 1].show_time : null
      // console.log(tasksList.value);
      console.log('tasksList', tasksList.value);
    }

    const saveData = () => {  
      return {
        ...toRaw(timeData),
        tasksList: toRaw(tasksList.value),
        oldTasksList: toRaw(oldTasksList.value)
      }
    }

    // 上一步
    const handlePrevStep = () => {
      emit('prevStep', saveData())
      track("task_capacity_assign_click", {
        button_type: "点击上一步",
      });
    }

    // 下一步
    const handleNextStep = () => {
      // 没有结束日期
      if(!timeData.endDate){
        return
      }
      emit('nextStep', saveData())
      track("task_capacity_assign_click", {
        button_type: "点击保存调整方案",
      });
    }

    const handleCheckWeek = (currentItem: weekTaskObject, flag = true) => {

      if (currentItem.isDisabled) {

        if (flag) {
          isPassTotal.value = true
        }
        return
      }
      if (timeData.weekChecked.includes(currentItem.value)) {
        if(tasksList.value.length === 1 && timeData.weekChecked.length === 1){
          // Toast('至少需要选择1天哦')
          timeData.weekChecked = timeData.weekChecked.filter((item: number) => item !== currentItem.value)
          calcEndDate()
          return
        }
        if (timeData.weekChecked.length === 1) {
          Toast('至少需要选择1天哦')
          track("task_capacity_assign_toast", {
            toast_type: "勾选的重复日超过最小限制",
          });
          return
        }
        timeData.weekChecked = timeData.weekChecked.filter((item: number) => item !== currentItem.value)
        track("task_capacity_assign_click", {
          button_type: "取消勾选重复日期选项",
        });
      } else {
        if (timeData.weekChecked.length === tasksList.value.length) {
          Toast(`本计划仅需${tasksList.value.length}次即可学完，最多选择${tasksList.value.length}天哦`)
          track("task_capacity_assign_toast", {
            toast_type: "勾选的重复日超过最大限制",
          });
          return
        }
        timeData.weekChecked.push(currentItem.value)
        track("task_capacity_assign_click", {
          button_type: "勾选重复日期选项",
        });
      }
      if (timeData.weekChecked.length > tasksList.value.length) {
        isPassTotal.value = true
        // Toast(`本计划仅需${tasksList.value.length}次即可学完，最多选择${tasksList.value.length}天哦`)
        timeData.weekList.map((item: weekTaskObject) => {
          if (!timeData.weekChecked.includes(item.value)) {
            item.isDisabled = true
          }
        })
      } else {
        if (flag) {
          isPassTotal.value = false
        }
        timeData.weekList.map((item: weekTaskObject) => {
          item.isDisabled = false
        })
      }
      calcEndDate()
    }

    // 重置数据
    const restData = () => {
      isPassTotal.value = false
      isShowCalc.value = false
      timeData.startDate = new Date()
      timeData.endDate = null
      timeData.weekChecked = []
      timeData.weekList.map((item: weekTaskObject) => {
        item.isDisabled = false
      })
      oldTasksList.value = []
      tasksList.value = []
    }

    // 任务列表
    watch(() => props.checkList, async (checkList: any) => {
      if (checkList && checkList.length == 0) return
      // if (props.saveData.startDate) {
      //   timeData.startDate = props.saveData.startDate
      //   timeData.endDate = props.saveData.endDate
      //   timeData.weekChecked = props.saveData.weekChecked
      //   timeData.weekList = props.saveData.weekList
      //   oldTasksList.value = props.saveData.oldTasksList
      //   await nextTick(() => {
      //     tasksList.value = props.saveData.tasksList
      //   })
      // }
      if (_.isEqual(checkList, oldTasksList.value)) {
        return
      }
      restData()
      await nextTick(() => {
        oldTasksList.value = _.cloneDeep(checkList)
        tasksList.value = _.cloneDeep(checkList).map((item: taskObject, index: number) => {
          item['key'] = index
          return item
        })

      })
    }, { deep: true, immediate: true })
    const updateDate = (value: any) => {
      console.log('updateDate', value);
      // timeData.startDate = value
      Toast(`日期调整成功`)
      track("task_capacity_assign_toast", {
        toast_type: "开始日调整成功",
      });
      onSelectedDate(value)
    }
    const onSelectedDate = (selectedDate: Date) => {
      timeData.startDate = selectedDate
      // isShowCalc.value = false
      calcEndDate()
    }
    const handleCalendarClick = () => {
      if (calendarRef.value) {
        // Your code here
        (calendarRef.value as any).openModal()
      }
    }
    return {
      calendarRef,
      date,
      transforWeek,

      isShowCalc,
      showCalc,
      isPassTotal,
      handleCancel,
      onSelectedDate,
      dayjs,
      timeData,
      handleCheckWeek,

      tasksList,

      handlePrevStep,
      handleNextStep,
      updateDate,
      handleCalendarClick
    }
  }
})
