import { ScheduleListItem, TreeListItem } from "@/views/UpdatePlan/types";

function useTree () {
  const getTreeChild = (treeList: any[], scheduleList: Array<any>) => {
    const list: Array<any> = [];
    for (const item of treeList) {
      if (isAddTask(scheduleList, item.course_id, item.content_id)) {
        list.push(item);
        continue;
      }

      if (item.childs && item.childs.length) {
        const childs = getTreeChild(item.childs, scheduleList);
        if (childs.length === 0) {
          continue;
        }
        list.push({
          ...item,
          childs,
        });
      }
    }

    return list;
  }
  
  function isAddTask (scheduleList: Array<ScheduleListItem>, course_id: string, content_id: string) {
    const taskList = scheduleList.filter((item) => item.content_id === course_id).map((item) => item.task_list);
    return taskList.flat().some(item => item.task_id === content_id);
  }

  return {
    getTreeChild,
    isAddTask
  };
}

export default useTree;