import {
    ContentsObject
  } from '../types2';
  
  export default () => {
    /**
     * @description: 获取扁平化树数据
     * @param {ContentsObject[]} treeList
     * @return {*}
     */  
    const getFlattenTreeData = (treeList: ContentsObject[]) => {
      const flattenTreeData: ContentsObject[] = []
      const recursion = (list: ContentsObject[]) => {
        list.forEach((node: ContentsObject) => {
          flattenTreeData.push(node)
          if (node.childs && node.childs.length) {
            recursion(node.childs)
          }
        })
      }
      recursion(treeList)
      return flattenTreeData
    }
    
    /**
     * @description: 过滤掉子级数据
     * @param {ContentsObject} treeList
     * @return {*}
     */  
    const removeChildsList = (treeList: ContentsObject[]) => {
      return treeList.map((node: ContentsObject) => {
        // node['parentBeforeChild'] = treeList.filter((item: ContentsObject) => node['parentKey'] === item['key'] && item['hasLastChild'] && item['floor'] !== 1).length ? true : false
        node['parentAfterChild'] = treeList.filter((item: ContentsObject) => node['parentKeys'].includes(item['key']) && !item['hasLastChild'] && item['floor'] !== 1).length ? false : true
        if (node.hasChildren) {
          node['capacity_value'] = treeList.filter((item: ContentsObject) => item.parentKeys.includes(node.key) && !item.hasChildren).reduce((total: any, item: any) => {
            return total + item.capacity_value
          }, 0)
          node.childs = []
        }
        return node
      })
    }
  
    const filterInitTreeData = (treeList: ContentsObject[]) => {
      function filterTreeNodes(source: ContentsObject[], level: number, path: string, parent?:ContentsObject) {
        const recursion = (list: ContentsObject[], level: number, parent?:ContentsObject) => {
          return list.map((node: ContentsObject, index: number) => {
            const parentKeys = parent ? [...parent.parentKeys, parent.key] : []
            node['checked'] = true
            node['checkedState'] = 'selected' // unSelected:未选中 selected:选中 halfSelected:半选
            node['floor'] = level
            node['key'] = `${path}-${index}`
            node['hasChildren'] = node.childs && node.childs.length ? true : false
            node['parentKey'] = parent ? parent.key : ''
            node['parentKeys'] = parentKeys
            node['myGroup'] = {name: 'site',pull: true,put: true}
            node['myArray'] = []
            node['hasLastChild'] = index === list.length - 1 ? true : false
            node['parentBeforeChild'] = parent ? parent['hasLastChild'] : false
            node['parentAfterChild'] = false
            node['childs'] = node.childs?.length ? filterTreeNodes(node.childs, level+1, node['key'], node) : []
            return node
          })
        }
        return recursion(source, level, parent)
      }
      const treeData = filterTreeNodes(treeList, 1, '1') // 过滤树数据
      const flattenTreeData = getFlattenTreeData(treeData) // 扁平化树数据
      const resultArr = removeChildsList(flattenTreeData) // 过滤掉子级数据
      return resultArr.map((item) => {
        return {
          ...item,
          course_id: item.course_id ? item.course_id : '0'
        };
      })
    }
  
    return {
      getFlattenTreeData,
      removeChildsList,
      filterInitTreeData
    }
  }