/**
 * 家庭激活设备列表
 */

export const getDeviceList = async () => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/privileges/v1/device/list', {
    token
  });
};


/**
 * 获取app下载信息
 * @param obj 
 * @returns 
 */
export const  downUrlConfig = async (params={}) => {
  return ApiService.post('/parent/api/v1/os/down-url-config-info', params);
}

/**
 * 检查领取状态
 * @returns 
 */
export const getClaimStatus = async (privilege_pkg_id: string, device_sn: string, privilege_id: string) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/privileges/v1/receive/check', {
    privilege_pkg_id,
    sn: device_sn,
    privilege_id,
    token
  });
}